private boolean _hasCustomHandlers(JavaType t) {
    if (t.isContainerType()) {
        // First: value types may have both value and type handlers
        JavaType ct = t.getContentType();
        if (ct != null) {
            if ((ct.getValueHandler() != null) || (ct.getTypeHandler() != null)) {
                return true;
            }
        }
        // Second: map(-like) types may have value or type handler for key
        if (t.isMapLikeType()) {
            JavaType kt = t.getKeyType();
            if (kt != null) {
                if ((kt.getValueHandler() != null) || (kt.getTypeHandler() != null)) {
                    return true;
                }
            }
        }
    }
    return false;
}

private boolean _hasCustomHandlers(JavaType t) {
    if (t.isContainerType()) {
        // First: value types may have both value and type handlers
        JavaType ct = t.getContentType();
        if (ct != null && ((ct.getValueHandler() != null) || (ct.getTypeHandler() != null))) {
            return true;
        }
        // Second: map(-like) types may have value handler for key (but not type; keys are untyped)
        if (t.isMapLikeType()) {
            JavaType kt = t.getKeyType();
            if (kt != null && kt.getValueHandler() != null) {
                return true;
            }
        }
    }
    return false;
}

private boolean _hasCustomHandlers(JavaType t) {
    if (t.isContainerType()) {
        // Check for custom key deserializer in map-like types
        if (t.isMapLikeType() && t.getKeyType() != null && t.getKeyType().getValueHandler() != null) {
            return true;
        }
        // Check for custom value and type handlers in content types
        JavaType ct = t.getContentType();
        if (ct != null && ((ct.getValueHandler() != null) || (ct.getTypeHandler() != null))) {
            return true;
        }
    }
    return false;
}
